const raw = $input.first().json.content?.[0]?.text || $input.first().json.response || '';
let parsed;
try {
  const clean = raw.replace(/^```json\n?/, '').replace(/\n?```$/, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  parsed = { avg_reply_rate: 'parse_error', best_opener_pattern: 'unknown', disqualify_signals: 'unknown', best_send_time: 'unknown', improvement_note: raw.slice(0,200), goal_hit_rate: 'unknown' };
}
return [{ json: parsed }];

const p = $input.first().json;
const SUPA_URL = $env.SUPABASE_URL;
const SUPA_KEY = $env.SUPABASE_KEY;
const hdrs = { 'apikey': SUPA_KEY, 'Authorization': `Bearer ${SUPA_KEY}`, 'Content-Type': 'application/json', 'Prefer': 'resolution=merge-duplicates,return=minimal' };

const updates = [
  { agent: 'Hermes', key: 'avg_reply_rate', value: p.avg_reply_rate, source: 'self_improve' },
  { agent: 'Hermes', key: 'best_opener_pattern', value: p.best_opener_pattern, source: 'self_improve' },
  { agent: 'Hermes', key: 'disqualify_signals', value: p.disqualify_signals, source: 'self_improve' },
  { agent: 'Hermes', key: 'best_send_time', value: p.best_send_time, source: 'self_improve' }
];

for (const u of updates) {
  await fetch(`${SUPA_URL}/rest/v1/agent_memory`, { method: 'POST', headers: hdrs, body: JSON.stringify(u) });
}

return [{ json: { ...p, memory_updated: true } }];
